class Solution {
public:
    string countOfAtoms(string formula) {
        int i = 0;
        auto parse = [&](auto&& self) -> map<string,int> {
            map<string,int> cnt;
            while (i < formula.size() && formula[i] != ')') {
                if (formula[i] == '(') {
                    ++i;
                    auto inner = self(self);
                    int num = 0;
                    while (i < formula.size() && isdigit(formula[i])) {
                        num = num * 10 + (formula[i++] - '0');
                    }
                    if (num == 0) num = 1;
                    for (auto& [k,v] : inner) cnt[k] += v * num;
                } else {
                    string elem;
                    elem += formula[i++];
                    while (i < formula.size() && islower(formula[i])) elem += formula[i++];
                    int num = 0;
                    while (i < formula.size() && isdigit(formula[i])) {
                        num = num * 10 + (formula[i++] - '0');
                    }
                    if (num == 0) num = 1;
                    cnt[elem] += num;
                }
            }
            ++i;
            return cnt;
        };
        auto res = parse(parse);
        string ans;
        for (auto& [k,v] : res) {
            ans += k;
            if (v > 1) ans += to_string(v);
        }
        return ans;
    }
};
